import dspy

from dspy.evaluate import Evaluate

class ParaphraseDriftDetector:
    def __init__(self, program):
        self.program = program
        self.paraphraser = dspy.ChainOfThought('question -> paraphrase')

    def detect_drift(self, examples, threshold=0.8):
        scores = []
        for ex in examples:
            original = self.program(ex)
            para_ex = self.paraphraser(ex.with_inputs('question'))
            para_result = self.program(para_ex)
            score = original.answer.similarity(para_result.answer)
            scores.append(score)
        drift_ratio = sum(s < threshold for s in scores) / len(scores)
        return {'drift_detected': drift_ratio > 0.3, 'drift_ratio': drift_ratio}

import re
from datetime import datetime

def monitor_assertions(dspy_output):
    violations = []

    # Date format assertion
    if 'date' in dspy_output.answer.lower():
        date_match = re.search(r'\d{4}-\d{2}-\d{2}', dspy_output.answer)
        if date_match:
            try:
                datetime.strptime(date_match.group(), '%Y-%m-%d')
            except:
                violations.append('invalid_date_format')

    # Numeric range assertion
    num_match = re.findall(r'\d+', dspy_output.answer)
    for num in num_match:
        if int(num) > 10000:  # Domain-specific threshold
            violations.append('out_of_range')

    return {'violations': violations, 'clean': len(violations) == 0}

