class AssertingModule(dspy.Module):
    def __init__(self, base_module, assertions):
        super().__init__()
        self.base_module = base_module
        self.assertions = assertions

    def forward(self, **kwargs):
        result = self.base_module(**kwargs)

        # Run assertions
        for assertion in self.assertions:
            if not assertion(result):
                result.observations['assertion_failed'] = assertion.__name__
                result.answer = f"[INVALID: {assertion.__name__}] {result.answer}"

        return result

